#include <bits/stdc++.h>
using namespace std;

const int N=5e5+10;

int n,d,x[N],s[N],k,q[N],hh,tt;
long long f[N],sum;

bool check(int g){
    memset(f,0xcf,sizeof(f));
    f[0]=0;
    hh=1,tt=0;
    for(int i=1,j=0;i<=n;i++){
        while(j<i && x[j]<=x[i]-(d-g)){
            while(hh<=tt && f[q[tt]]<=f[j]) tt--;
            q[++tt]=j,j++;
        }
        while(hh<=tt && x[q[hh]]<x[i]-(d+g)) hh++;
        if(hh<=tt) f[i]=f[q[hh]]+s[i];
        if(f[i]>=k)
            return true;
    }
    return false;
}

int main(){
    scanf("%d%d%d",&n,&d,&k);
    for(int i=1;i<=n;i++){
        scanf("%d%d",&x[i],&s[i]);
        sum+=max(0,s[i]);
    }
    if(sum<k){
        printf("-1");
        return 0;
    }
    int l=0,r=1e9;
    while(l<r){
        int mid=l+r>>1;
        if(check(mid))
            r=mid;
        else
            l=mid+1;
    }
    printf("%d",l);
    return 0;
}
